  "claims": [
    {
      "claim_text": "草莓是一种常见的浆果类水果，颜色鲜红，味道酸甜，香气明显。它既适合直接食用，也常用于制作甜点、饮品、果酱和水果沙拉。",
      "citation_locator": "line:5",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓含有较丰富的维生素 C。",
      "citation_locator": "line:21",
      "confidence_status": "cited"
    },
    {
      "claim_text": "在常见水果中，草莓的维生素 C 表现较好，是一种适合作为日常补充的水果。",
      "citation_locator": "line:23",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓中含有一定膳食纤维，有助于增加饱腹感。",
      "citation_locator": "line:27",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓鲜红的颜色与其中的天然色素和植物化合物有关。",
      "citation_locator": "line:31",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓品种较多，不同品种在大小、甜度、酸度、香气和口感上会有差异。",
      "citation_locator": "line:35",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓表面比较娇嫩，清洗和保存时都需要注意。",
      "citation_locator": "line:71",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓建议吃之前再清洗，不要提前大量清洗后存放。",
      "citation_locator": "line:75",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓适合冷藏保存。",
      "citation_locator": "line:86",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓果肉较软，受到挤压后容易破损、出水、变质。",
      "citation_locator": "line:90",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓适合大多数人群食用，尤其适合喜欢酸甜口感、希望增加水果种类的人。",
      "citation_locator": "line:94",
      "confidence_status": "cited"
    },
    {
      "claim_text": "对草莓过敏的人不应食用。",
      "citation_locator": "line:98",
      "confidence_status": "cited"
    },
    {
      "claim_text": "胃肠较敏感的人，不建议一次吃太多。",
      "citation_locator": "line:99",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓表面容易残留泥沙，食用前应认真清洗。",
      "citation_locator": "line:100",
      "confidence_status": "cited"
    },
    {
      "claim_text": "草莓发霉、变软出水、有异味时不应继续食用。",
      "citation_locator": "line:101",
      "confidence_status": "cited"
    },
    {
      "claim_text": "血糖控制要求较高的人，应注意总水果摄入量。",
      "citation_locator": "line:102",
      "confidence_status": "cited"
    }
  ],
  "concept": {
    "title": "草莓",
    "aliases": [
      "草莓（水果）",
      "草莓：酸甜可口的浆果类水果"
    ]
  },
